    """Return sorted unique elements in a list
    >>> unique_sorted_by([(5, 1), (3, 2), (5, 3), (2, 4), (3, 5), (3, 6), (9, 7), (0, 8), (123, 9)], lambda x: x[0])
    [(0, 8), (2, 4), (3, 6), (5, 1), (9, 7), (123, 9)]
    """
    return sorted(set(l), key=key)

